interface IconProps {
  name: string;
  size?: number;
  color?: string;
  className?: string;
}

export const Icon: React.FC<IconProps> = ({
  name,
  size = 18,
  color = "currentColor",
  className = "",
}) => {
  const paths = ICON_PATHS[name];

  if (!paths) {
    console.warn(`[Icon] "${name}" is not a valid QDS3 icon.`);
    // Fallback placeholder
    return (
      <svg
        width={size}
        height={size}
        viewBox="0 0 24 24"
        fill="none"
        className={className}
        aria-label={name}
        role="img"
      >
        <circle
          cx="12"
          cy="12"
          r="10"
          stroke={color}
          strokeWidth="1.5"
          opacity="0.3"
        />
        <text x="12" y="16" textAnchor="middle" fill={color} fontSize="10">
          {name.replace("Icon", "").charAt(0)}
        </text>
      </svg>
    );
  }

  return (
    <svg
      width={size}
      height={size}
      viewBox="0 0 24 24"
      fill="none"
      style={{ color }}
      className={className}
      aria-label={name}
      role="img"
    >
      {paths}
    </svg>
  );
};
